mapper.select:
SELECT * FROM poetry


        (title LIKE CONCAT('%', #{keyword}, '%') 
        OR author LIKE CONCAT('%', #{keyword}, '%') 
        OR content LIKE CONCAT('%', #{keyword}, '%'))


        AND dynasty = #{dynasty}


        AND author = #{author}


        AND id IN (
            SELECT poetry_id FROM poetry_tag 
            JOIN tag ON poetry_tag.tag_id = tag.id 
            WHERE tag.type = 'genre' AND tag.name = #{genre}
        )


        AND id IN (
            SELECT poetry_id FROM poetry_tag 
            JOIN tag ON poetry_tag.tag_id = tag.id 
            WHERE tag.type = 'theme' AND tag.name = #{theme}
        )


ORDER BY id DESC
